using System;using System.Collections.Generic;using System.Linq;class A{static string[]R=new string[4];static int PL,NB,MB;static bool H0(int i,int a,int b){for(int j=a;j<b&&j<PL;j++)if(R[i][j]=='0')return true;return false;}static int[]Sim(int[]L,int x,int sp,string act){var n=(int[])L.Clone();if(act=="SPEED")sp++;if(act=="SLOW")sp--;if(act=="SPEED"||act=="SLOW"||act=="WAIT"){for(int i=0;i<4;i++)if(n[i]==1&&H0(i,x,x+sp))n[i]=0;x+=sp;}else if(act=="JUMP"){for(int i=0;i<4;i++)if(n[i]==1&&(R[i][x]=='0'||(x+sp<PL&&R[i][x+sp]=='0')))n[i]=0;x+=sp;}else if(act=="UP"){if(n[0]==1){for(int i=0;i<4;i++)if(n[i]==1&&H0(i,x,x+sp))n[i]=0;}else for(int i=1;i<4;i++){if(n[i-1]==0&&n[i]==1){if(H0(i-1,x,x+sp)||H0(i,x,x+sp)){n[i-1]=0;n[i]=0;}else{n[i-1]=1;n[i]=0;}}else if(n[i-1]==1&&n[i]==1){if(H0(i-1,x,x+sp))n[i-1]=0;if(H0(i,x,x+sp))n[i]=0;}}x+=sp;}else{if(n[3]==1){for(int i=0;i<4;i++)if(n[i]==1&&H0(i,x,x+sp))n[i]=0;}else for(int i=2;i>=0;i--){if(n[i+1]==0&&n[i]==1){if(H0(i,x,x+sp)||H0(i+1,x,x+sp)){n[i+1]=0;n[i]=0;}else{n[i+1]=1;n[i]=0;}}else if(n[i+1]==1&&n[i]==1){if(H0(i+1,x,x+sp))n[i+1]=0;if(H0(i,x,x+sp))n[i]=0;}}x+=sp;}return new[]{n[0],n[1],n[2],n[3],x,sp};}static void Main(){NB=int.Parse(Console.ReadLine());MB=int.Parse(Console.ReadLine());for(int i=0;i<4;i++)R[i]=Console.ReadLine()+new string('.',50);PL=R[0].Length;var F=new List<string>();var acts=new[]{"SPEED","JUMP","WAIT","UP","DOWN","SLOW"};for(;;){if(F.Count>0){Console.ReadLine();for(int i=0;i<NB;i++)Console.ReadLine();Console.WriteLine(F[0]);F.RemoveAt(0);continue;}var p=Console.ReadLine().Split(' ');int sp=int.Parse(p[0]);var L=new int[4];int bx=0;for(int i=0;i<NB;i++){p=Console.ReadLine().Split(' ');int x=int.Parse(p[0]),y=int.Parse(p[1]),a=int.Parse(p[2]);L[y]=a;if(a==1)bx=x;}var q=new List<(int[],int,int,List<string>)>{((int[])L.Clone(),bx,sp,new List<string>())};int[]best=null;List<string>ba=null;for(int it=0;it<30&&q.Count>0;it++){var nq=new List<(int[],int,int,List<string>)>();foreach(var(cl,cx,cs,ca)in q)foreach(var act in acts){var r=Sim(cl,cx,cs,act);int nb=r[0]+r[1]+r[2]+r[3];if(nb<MB||r[5]<1)continue;var na=new List<string>(ca){act};if(r[4]>=PL-30){if(best==null||nb>best[0]+best[1]+best[2]+best[3]){best=r;ba=na;}continue;}nq.Add((new[]{r[0],r[1],r[2],r[3]},r[4],r[5],na));}nq.Sort((a,b)=>(b.Item1.Sum()*b.Item2).CompareTo(a.Item1.Sum()*a.Item2));if(nq.Count>200)nq.RemoveRange(200,nq.Count-200);q=nq;if(best!=null)break;}F=ba??new List<string>{"SPEED"};Console.WriteLine(F[0]);F.RemoveAt(0);}}}